select count(*) from postgres.posthistory as ph, postgres.votes as v, postgres.users as u, postgres.badges as b where u.id = b.userid and u.id = ph.userid and u.id = v.userid and ph.posthistorytypeid=1 and v.creationdate<=timestamp '2014-09-12 00:00:00' and u.reputation<=126 and u.views<=11 and u.creationdate>=timestamp '2010-08-02 16:17:58' and u.creationdate<=timestamp '2014-09-12 00:16:30' and b."date"<=timestamp '2014-09-03 16:13:12';
